import { useState } from "react";
import AppShell from "../components/AppShell";
import EmptyState from "../components/EmptyState";
import PageHeader from "../components/PageHeader";
import SearchFilterBar from "../components/SearchFilterBar";
import SectionCard from "../components/SectionCard";
import SegmentTabs from "../components/SegmentTabs";

export default function PatientHistoryPage() {
  const [tab, setTab] = useState("All");
  const [search, setSearch] = useState("");

  return (
    <AppShell>
      <PageHeader
        title="Patient History"
        subtitle="Review monitoring timelines, historical readings, and alert events."
        tabs={
          <SegmentTabs
            tabs={["All", "Normal", "Warning", "Critical", "Reviewed", "Closed"]}
            value={tab}
            onChange={setTab}
          />
        }
        filters={
          <SearchFilterBar
            searchValue={search}
            onSearchChange={setSearch}
            searchPlaceholder="Search by patient ID"
            filters={[
              { label: "Date range", value: "all", disabled: true, onChange: () => {}, options: [{ value: "all", label: "History endpoint required" }] },
              { label: "Severity", value: "all", disabled: true, onChange: () => {}, options: [{ value: "all", label: "History endpoint required" }] },
              { label: "Device", value: "all", disabled: true, onChange: () => {}, options: [{ value: "all", label: "History endpoint required" }] },
            ]}
            onClear={() => setSearch("")}
          />
        }
      />

      <SectionCard title="Case History Timeline" subtitle="Chronological patient monitoring events, reviews, and device state changes.">
        <EmptyState
          icon="history"
          title="No history recorded for this patient yet."
          message="A history or patient timeline endpoint is required before the console can render monitoring periods, reviews, and resolution events."
        />
      </SectionCard>
    </AppShell>
  );
}
